text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        "이번 주 안에 테마 패키지 준비를 목표로 하며, 공개 릴리스는 smoke test 통과 시 금요일 15:00 KST로 확정한다.",
        "packageName mismatch가 발생하면 smoke-theme-pack.mjs에서 즉시 무시 처리하지 않는다. 먼저 패키지 설정(계약/구성)을 우선 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      ],
      "rejected_proposals": [
        "Hara가 제안한 'smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경' 제안은 거부됨."
      ],
      "internal_stretch_goals": [
        "수요일 공개 릴리스 가능성은 내부 stretch goal로만 고려되었고, 확정 일정이 아니다."
      ]
    },
    "non_decisions": [
      "README install 단계 검토는 필요한 과제로 언급되었으나 담당자 및 확정 기한이 지정되지 않았다.",
      "Hara의 tarball 경로 확인은 Minjun 결과 공유 후 진행하되, 구체 기한은 미정이다."
    ],
    "risks": [
      {
        "description": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "description": "README 설치 단계가 오래된 내용이면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 Wednesday stretch goal을 언급할지 여부가 미결정이다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test 재실행 후 금요일 10:00 KST까지 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트 작성 후 action_items.md 반영",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 공유 후 생성된 tarball 경로 확인",
      "due": "minjun 결과 공유 후(정확한 시간 미정)",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README install steps 검토",
      "due": "미정(목요일 가능 시)",
      "status": "open",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST smoke 결과 수신 후 Hara의 tarball 경로 확인 작업 진행",
      "Doyun의 실패 트리아지 노트(action_items.md) 반영 상태 확인",
      "최종 릴리스 승인자 확정(미결 질문) 및 승인 플로우 정렬",
      "릴리스 노트 문구에 내부 stretch goal(수요일) 반영 여부 최종 결정"
    ],
    "what_not_to_invent": [
      "고객명, 예산, 보안 사고, 운영 장애, 법무 승인 등 회의 메모에 없는 사실 추가 금지",
      "owner나 마감일이 언급되지 않은 항목에 대한 임의 추정 금지",
      "거부된 제안(패키지명 불일치 무시 처리)을 확정 결정으로 바꿔 기록하지 않음"
    ]
  },
  "non_invention_rules": [
    "원문에 명시되지 않은 고객, 예산, 보안, 장애, 법무 승인 관련 정보를 추가하지 않는다.",
    "owner가 없는 항목은 미지정으로 남기고, 담당자를 추정해 넣지 않는다.",
    "확정된 due 날짜/시간만 사용하고, 없는 항목에 임의 날짜를 생성하지 않는다.",
    "제안(특히 거부된 제안)과 확정 결정을 별도 항목으로 분리해 기록한다.",
    "내부 stretch goal은 최종 일정으로 오인되지 않게 명시적으로 구분한다."
  ]
}
